// renderOperationGroups renders optional operation flags grouped by their
// "speakeasy:group" annotation. Groups are shown alphabetically, with
// ungrouped flags under a generic "Optional Flags" header.
func renderOperationGroups(flags *pflag.FlagSet) string {
	groups := make(map[string]*pflag.FlagSet)
	groupOrder := []string{}
	ungrouped := pflag.NewFlagSet("ungrouped", pflag.ContinueOnError)

	flags.VisitAll(func(f *pflag.Flag) {
		if f.Hidden {
			return
		}
		if ann, ok := f.Annotations["speakeasy:group"]; ok && len(ann) > 0 {
			name := ann[0]
			if _, exists := groups[name]; !exists {
				groups[name] = pflag.NewFlagSet(name, pflag.ContinueOnError)
				groupOrder = append(groupOrder, name)
			}
			groups[name].AddFlag(f)
		} else {
			ungrouped.AddFlag(f)
		}
	})

	var buf strings.Builder

	// Show ungrouped optional flags first
	if ungrouped.HasFlags() {
		buf.WriteString("Optional Flags:\n")
		buf.WriteString(ungrouped.FlagUsages())
	}

	// Then show each group
	for _, name := range groupOrder {
		fs := groups[name]
		if !fs.HasFlags() {
			continue
		}
		buf.WriteString("\n" + name + " Flags:\n")
		buf.WriteString(fs.FlagUsages())
	}

	return buf.String()
}

